refsection.programlisting:
url = "https://imagej.net/ij/images/mri-stack.zip";
zipFile = fullfile(TMPDIR, "ipcv_mri-stack.zip");
outDir = fullfile(TMPDIR, "ipcv_mri-stack");
stackFile = fullfile(outDir, "mri-stack.tif");

if ~isfile(zipFile) then
    http_get(url, zipFile, follow=%t, timeout=120);
end

if ~isfile(stackFile) then
    if ~isdir(outDir) then
        mkdir(outDir);
    end
    decompress(zipFile, outDir);
end

stack = imreadmulti(stackFile);
volume = squeeze(stack(:, :, 1, :));

startPoint = [45 35 6];
cropSize = [140 120 16];
cropped = imcrop3(volume, startPoint, cropSize);

mprintf("input MRI volume : %d x %d x %d\n", size(volume, 1), size(volume, 2), size(volume, 3));
mprintf("cropped volume   : %d x %d x %d\n", size(cropped, 1), size(cropped, 2), size(cropped, 3));

subplot(2, 3, 1);
imshow(volume(:, :, startPoint(3)));
title("MRI slice 6");
subplot(2, 3, 2);
imshow(volume(:, :, startPoint(3) + round(cropSize(3) / 2)));
title("MRI middle");
subplot(2, 3, 3);
imshow(volume(:, :, startPoint(3) + cropSize(3) - 1));
title("MRI slice 21");

subplot(2, 3, 4);
imshow(cropped(:, :, 1));
title("Cropped slice 1");
subplot(2, 3, 5);
imshow(cropped(:, :, round(size(cropped, 3) / 2)));
title("Cropped middle");
subplot(2, 3, 6);
imshow(cropped(:, :, size(cropped, 3)));
title("Cropped last");
